import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-agentic-rag'
});

const queryPlannerCallback = async (context: any, cb: any) => {
  const { input, output } = context;

  const result = await vex.verify({
    session: input.sessionId,
    step: 'query_planning',
    input: input.question,
    output: output.subQueries,
    checks: [
      {
        type: 'query_planning_accuracy',
        threshold: 0.8,
        config: { originalQuery: input.question }
      }
    ]
  });

  if (!result.pass) {
    cb(null, { error: 'Invalid query plan', subQueries: [] });
    return;
  }

  cb(null, output);
};

const retrievalCallback = async (context: any, cb: any) => {
  const { input, output } = context;

  const verification = await vex.verify({
    session: input.sessionId,
    step: 'document_retrieval',
    input: input.query,
    output: output.documents,
    checks: [
      {
        type: 'source_relevance',
        threshold: 0.7,
        config: { query: input.query, minDocs: 3 }
      },
      {
        type: 'source_diversity',
        threshold: 0.6
      }
    ]
  });

  if (verification.pass) {
    cb(null, { documents: verification.filteredOutput });
  } else {
    cb(null, { documents: [], warning: 'Insufficient relevant sources' });
  }
};

const synthesisCallback = async (context: any, cb: any) => {
  const result = await vex.verify({
    session: context.sessionId,
    step: 'multi_source_synthesis',
    input: {
      sources: context.sources,
      query: context.originalQuery
    },
    output: context.synthesizedAnswer,
    checks: [
      {
        type: 'cross_source_consistency',
        threshold: 0.75,
        config: { sources: context.sources }
      },
      {
        type: 'hallucination_detection',
        threshold: 0.9
      }
    ]
  });

  cb(null, {
    answer: result.pass ? context.synthesizedAnswer : null,
    citations: result.citations,
    score: result.score
  });
};

const citationCallback = async (context: any, cb: any) => {
  const finalCheck = await vex.verify({
    session: context.sessionId,
    step: 'citation_verification',
    input: context.answer,
    output: context.citations,
    checks: [
      {
        type: 'source_faithfulness',
        threshold: 0.85,
        config: { requireCoverage: 0.9 }
      },
      {
        type: 'citation_accuracy',
        threshold: 0.95
      }
    ]
  });

  if (finalCheck.pass) {
    cb(null, {
      finalAnswer: context.answer,
      verifiedCitations: finalCheck.validCitations,
      confidence: finalCheck.overallScore
    });
  } else {
    cb(null, {
      finalAnswer: 'Unable to verify response with sufficient evidence',
      citations: [],
      confidence: 0
    });
  }
};

