const flowiseConfig = {
  chatflows: {
    agenticRAG: {
      nodes: {
        'query-planner': {
          callbacks: [queryPlannerCallback]
        },
        'vector-store-1': {
          callbacks: [retrievalCallback]
        },
        'vector-store-2': {
          callbacks: [retrievalCallback]
        },
        'synthesis-agent': {
          callbacks: [synthesisCallback]
        },
        'final-answer': {
          callbacks: [citationCallback]
        }
      }
    }
  }
};

// Initialize Vex globally
Vex.init({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-agentic-rag',
  autoSession: true
});

class VexGuardedToolNode {
  async executeTool(input: any, sessionId: string) {
    try {
      const toolResult = await this.originalTool(input);

      const verified = await vex.verify({
        session: sessionId,
        step: 'custom_tool',
        input,
        output: toolResult,
        checks: [{ type: 'tool_output_validity', threshold: 0.8 }]
      });

      return verified.pass ? verified.output : this.getFallback(input);
    } catch (error) {
      await vex.captureError({
        session: sessionId,
        step: 'custom_tool',
        error: error.message,
        input
      });
      return this.getFallback(input);
    }
  }

  private getFallback(input: any) {
    return {
      content: 'Tool temporarily unavailable. Using cached knowledge.',
      source: 'fallback',
      confidence: 0.3
    };
  }
}

const sessionMetrics = async (sessionId: string) => {
  const metrics = await vex.getSessionMetrics(sessionId, {
    timeWindow: '1h',
    filters: {
      useCase: 'agentic_rag',
      checks: ['source_faithfulness', 'hallucination_detection']
    }
  });

  return {
    overallPassRate: metrics.passRate,
    criticalFailures: metrics.checks['source_faithfulness'].failures,
    avgConfidence: metrics.avgScore,
    topIssues: metrics.issues.slice(0, 5),
    recommendation: metrics.autoFixes
  };
};

// Usage in Flowise API endpoint
app.post('/chat', async (req, res) => {
  const sessionId = req.body.sessionId;
  const response = await chatflow.chat(req.body);

  const metrics = await sessionMetrics(sessionId);

  res.json({
    ...response,
    _vexMetrics: metrics
  });
});
